import './styles.css'
import { useProgressQueue } from './useProgressBarQueue';
import ProgressBar from './ProgressBar'

function ProgressBars() {
    const { queue, addBar } = useProgressQueue(3000);

    return (
        <>
            <div>
                {queue.map((progress, idx) => (
                    <ProgressBar key={idx} progress={progress} />
                ))}
            </div>
            <button onClick={addBar}>+Add</button>
        </>
    )
}

export default ProgressBars
